};

const ColorModeWrapper = ({ children, globals, context }) => {
  const { setColorMode } = useColorMode();

  useEffect(() => {
    setColorMode(globals.colorMode);

    // Add class to change tailwind components to respect color mode
    const selector =
      context.viewMode === 'docs' ? `#anchor--${context.id} .sb-story` : '#storybook-root';
    const container = document.querySelector(selector);

    if (globals.colorMode === 'dark') {
      container.classList.add('dark');
    } else {
      container.classList.remove('dark');
    }
  }, [globals.colorMode]);

  return children;
};

export const decorators = [
  (Story, { globals, parameters, ...context }) => {
    const chakraTheme = useMemo(() => {
      const newTheme = { ...theme };
      newTheme.colorMode = globals.colorMode;
      return newTheme;
    }, [globals.colorMode]);

    useEffect(() => {
      i18n.changeLanguage(globals.locale);
    }, [i18n, globals.locale]);

    const queryClient = new QueryClient();

    useEffect(() => {
      Object.defineProperty(window.document, 'cookie', {
        writable: true,
        value: `userId=${MOCK_USER_ID}`,
      });
    }, []);

    return (
      <SuspenseLoading>
        <QueryClientProvider client={queryClient}>
          <ChakraProvider theme={chakraTheme}>
            <ColorModeWrapper globals={globals} context={context}>
              <MemoryRouter initialEntries={[`/accounts/1`]}>
                <Routes>
                  <Route
                    path="accounts/:accountId"
                    element={
                      <Panel variant="primary" size="full" rounded={0} height="full">
                        <Box overflowY="auto" width="full" height="full">
                          {Story()}
                        </Box>
                      </Panel>
                    }
                  />
                </Routes>
              </MemoryRouter>
            </ColorModeWrapper>
          </ChakraProvider>
        </QueryClientProvider>
      </SuspenseLoading>
    );
  },
];

